// JavaScript implementation for Blockchain Developer Core Principles Part 5A
async function handleExecution(payload) {
  try {
    const response = await fetch('/api/data', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    const data = await response.json();
    console.log('Blockchain Developer Core Principles Part 5A status:', data.success);
    return data;
  } catch (err) {
    console.error('Execution error:', err);
  }
}

handleExecution({ item: 'Blockchain Developer Core Principles Part 5A' });
